spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var colOnes = W / 2 - 35;
    var colDot = W / 2 - 12;
    var colTenths = W / 2 + 10;
    var colHund = W / 2 + 35;

    var rowBorrow = H / 2 - 45;
    var rowVal1 = H / 2 - 25;
    var rowVal2 = H / 2 - 2;
    var rowLine = H / 2 + 16;
    var rowSum = H / 2 + 36;

    // Stages
    // 0 - 2s: Stage 1 (Setup numbers, highlight dots, pad zero)
    // 2s - 4.5s: Stage 2 (Borrow to hundredths: 10 - 5 = 5)
    // 4.5s - 7s: Stage 3 (Borrow to tenths: 12 - 7 = 5)
    // 7s - 9.5s: Stage 4 (Subtract ones: 4 - 1 = 3)
    // 9.5s - 12s: Stage 5 (Decimal drop down & final result)

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    // Helper for columns highlight
    function highlightCol(colX, width) {
      ctx.fillStyle = 'rgba(236, 72, 153, 0.12)'; // Pink highlight for subtraction
      ctx.fillRect(colX - width / 2, H / 2 - 55, width, 105);
    }

    if (stage === 2) highlightCol(colHund, 22);
    if (stage === 3) highlightCol(colTenths, 22);
    if (stage === 4) highlightCol(colOnes, 22);

    ctx.font = 'bold 18px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Operator
    ctx.fillStyle = '#9CA3AF';
    ctx.fillText('-', W / 2 - 62, rowVal2);

    // Top row values (5 . 3 0)
    // Note: slash them out if borrowed
    ctx.fillStyle = (stage >= 4) ? '#4B5563' : '#F3F4F6';
    ctx.fillText('5', colOnes, rowVal1);
    if (stage >= 4) {
      // draw slash
      ctx.beginPath(); ctx.moveTo(colOnes - 6, rowVal1 + 6); ctx.lineTo(colOnes + 6, rowVal1 - 6);
      ctx.strokeStyle = '#EF4444'; ctx.lineWidth = 1.5; ctx.stroke();
    }

    ctx.fillStyle = (stage === 1 || stage === 5) ? '#F59E0B' : '#F3F4F6';
    ctx.fillText('.', colDot, rowVal1);

    ctx.fillStyle = (stage >= 3) ? '#4B5563' : '#F3F4F6';
    ctx.fillText('3', colTenths, rowVal1);
    if (stage >= 3) {
      // draw slash
      ctx.beginPath(); ctx.moveTo(colTenths - 6, rowVal1 + 6); ctx.lineTo(colTenths + 6, rowVal1 - 6);
      ctx.strokeStyle = '#EF4444'; ctx.lineWidth = 1.5; ctx.stroke();
    }

    // Padded 0
    ctx.fillStyle = (stage >= 2) ? '#4B5563' : '#60A5FA';
    ctx.fillText('0', colHund, rowVal1);
    if (stage >= 2) {
      // draw slash
      ctx.beginPath(); ctx.moveTo(colHund - 6, rowVal1 + 6); ctx.lineTo(colHund + 6, rowVal1 - 6);
      ctx.strokeStyle = '#EF4444'; ctx.lineWidth = 1.5; ctx.stroke();
    }

    // Bottom row values (1 . 7 5)
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('1', colOnes, rowVal2);
    ctx.fillText('.', colDot, rowVal2);
    ctx.fillText('7', colTenths, rowVal2);
    ctx.fillText('5', colHund, rowVal2);

    // Separator Line
    ctx.beginPath();
    ctx.moveTo(W / 2 - 70, rowLine);
    ctx.lineTo(W / 2 + 50, rowLine);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2.5;
    ctx.stroke();

    // Borrow Row digits
    ctx.font = '12px -apple-system, sans-serif';
    if (stage === 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('10', colHund, rowBorrow);
      ctx.fillText('2', colTenths, rowBorrow);
    } else if (stage === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('12', colTenths, rowBorrow);
      ctx.fillText('4', colOnes, rowBorrow);
    } else if (stage >= 4) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('4', colOnes, rowBorrow);
    }

    // Sum/Difference Row digits
    ctx.font = 'bold 18px -apple-system, sans-serif';
    if (stage >= 2) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('5', colHund, rowSum);
    }
    if (stage >= 3) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('5', colTenths, rowSum);
    }
    if (stage >= 5) {
      ctx.fillStyle = '#EF4444';
      ctx.fillText('.', colDot, rowSum);
    }
    if (stage >= 4) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('3', colOnes, rowSum);
    }

    // Bottom instructional labels
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Lining Up and Padding Zeros', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('5.3 is padded with a zero to become 5.30', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#EC4899';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Borrow to Hundredths Column', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Borrow 1 tenth: 3 tenths -> 2. 0 becomes 10. 10 - 5 = 5.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#EC4899';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Borrow to Tenths Column', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('2 < 7. Borrow 1 whole: 5 -> 4. 2 becomes 12. 12 - 7 = 5.', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Subtract Ones Column', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('4 ones - 1 one = 3 ones', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Difference = 3.55', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Drop the decimal point straight down', W / 2, H - 22);
    }
  }
};
